        self._accent_swatch = tk.Label(row_ac, bg=ACCENT, width=4, cursor="hand2", relief="flat")
        self._accent_swatch.pack(side="right")
        self._accent_swatch.bind("<Button-1>", self._pick_accent)
        tk.Label(row_ac, text="  ↑ click", fg=MUTED, bg=BG2, font=self._f(7)).pack(side="right")

